// T607 TenantQuotaMaterializer — atomic quota write via MULTI/EXEC
async materializeQuota(tier: string): Promise<DataProcessResult<void>> {
  const tenantId = this.tenantContext.getTenantId(); // ALS only

  // Load tier definition from FREEDOM — no hardcoded values
  const tierDef = await this.freedom.getConfig(`tenant_quota_tier_${tier}`); // F1522

  // Build quota key map from tier definition
  const rawKeyMap = new Map<string, number>(Object.entries(tierDef));

  // QUOTA_KEY_FILTER: exclude non-quota keys from MULTI/EXEC
  const quotaKeyMap = new Map(
    [...rawKeyMap.entries()].filter(([k]) => k.startsWith(`quota:${tenantId}:`))
  );

  if (quotaKeyMap.size === 0) {
    return DataProcessResult.failure('NO_QUOTA_KEYS', 'Tier definition produced no quota keys');
  }

  // MULTI/EXEC — atomic, all or nothing
  const multi = this.quotaStore.multi(); // F1524
  for (const [key, value] of quotaKeyMap.entries()) {
    multi.set(key, String(value)); // no individual await — queued in MULTI
  }
  await multi.exec(); // atomic commit

  await this.queue.enqueue('TenantQuotaMaterialized', {
    tenantId,
    tier,
    keyCount: quotaKeyMap.size,
    materializedAt: new Date().toISOString(),
  });
  return DataProcessResult.success();
}
